const nacl = require("tweetnacl");
const { Buffer } = require('buffer');

const PUBLIC_KEY = '051f49a7773374dcb252d1ad2af3a2c913581e5916265a70d58c57e598a6e652';
const webhookData = $('Webhook1').first().json;

const signature = webhookData.headers["x-signature-ed25519"];
const timestamp  = webhookData.headers["x-signature-timestamp"];
const body = JSON.stringify(webhookData.body);

const isVerified = nacl.sign.detached.verify(
  Buffer.from(timestamp + body),
  Buffer.from(signature, "hex"),
  Buffer.from(PUBLIC_KEY, "hex")
);

if (!isVerified) {
  return [{ json: { type: 0 } }];
}

if (webhookData.body.type === 1) {
  return [{ json: { type: 1 } }];
}

return [{ json: webhookData }];

